// ── Main Component ─────────────────────────────────────────────────────────────
export default function OpsRoom() {
  const [time, setTime] = useState(new Date());
  const [activePanel, setActivePanel] = useState("political");
  const [defconRegion, setDefconRegion] = useState("ksa");
  const [aiLoading, setAiLoading] = useState(false);
  const [aiText, setAiText] = useState("");
  const [newsIdx, setNewsIdx] = useState(0);
  const [alertPulse, setAlertPulse] = useState(false);

  // Clock
  useEffect(() => {
    const t = setInterval(() => setTime(new Date()), 1000);
    return () => clearInterval(t);
  }, []);

  // Alert pulse every 8s
  useEffect(() => {
    const t = setInterval(() => {
      setAlertPulse(p => !p);
    }, 8000);
    return () => clearInterval(t);
  }, []);

  // News cycle
  const allEvents = PANELS.flatMap(p => p.events.map(e => ({ ...e, panel: p.title, color: p.color })));
  useEffect(() => {
    const t = setInterval(() => setNewsIdx(i => (i + 1) % allEvents.length), 3500);
    return () => clearInterval(t);
  }, []);

  const saudiTime = time.toLocaleTimeString("ar-SA", {
    timeZone: "Asia/Riyadh", hour: "2-digit", minute: "2-digit", second: "2-digit", hour12: false,
  });
  const saudiDate = time.toLocaleDateString("ar-SA", {
    timeZone: "Asia/Riyadh", weekday: "long", year: "numeric", month: "long", day: "numeric",
  });

  const panel = PANELS.find(p => p.id === activePanel);
  const region = DEFCON_REGIONS.find(r => r.id === defconRegion);
  const defcon = DEFCON_META[region?.level || 5];

  // Claude AI compound analysis
  const fetchCompoundAI = useCallback(async () => {
    setAiLoading(true);
    setAiText("");
    const triggers = panel.events.slice(0, 2).map(e => e.text).join(" + ");
    try {
      const res = await fetch("https://api.anthropic.com/v1/messages", {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          model: "claude-sonnet-4-20250514",
          max_tokens: 1000,
          system: "أنت محلل استراتيجي رفيع متخصص في منطقة الشرق الأوسط. قدم تحليلاً مركّباً موجزاً (3-4 جمل) يجمع المتغيرات السياسية والاقتصادية والتقنية في قراءة واحدة مع تحديد الفرصة أو المخاطرة الرئيسية.",
          messages: [{ role: "user", content: `حلل هذه التطورات المتزامنة في غرفة العمليات:\n${triggers}\n\nاللوحة: ${panel.title}\nمؤشرات: ${panel.metrics.map(m => m.label + ": " + m.val + m.unit).join(" | ")}` }],
        }),
      });
      const data = await res.json();
      setAiText(data.content?.find(c => c.type === "text")?.text || "لا يمكن إجراء التحليل حالياً.");
    } catch {
      setAiText("تعذّر الاتصال بمحرك التحليل.");
    }
    setAiLoading(false);
  }, [panel]);

  return (
    <div className="ops-root" style={{
      fontFamily: "\'IBM Plex Sans Arabic\', \'Tajawal\', sans-serif",
      background: "#060d18",
      minHeight: "100vh",
      color: "#e2e8f0",
      direction: "rtl",
      display: "flex",
      flexDirection: "column",
      overflow: "hidden",
    }}>
      <style>{`
        @import url(\'https://fonts.googleapis.com/css2?family=IBM+Plex+Sans+Arabic:wght@300;400;500;600;700&display=swap\');
        .ops-root, .ops-root * { box-sizing: border-box; margin: 0; padding: 0; }
        ::-webkit-scrollbar { width: 3px; }
        ::-webkit-scrollbar-thumb { background: #1e293b; border-radius: 2px; }
        @keyframes pulse { 0%,100%{opacity:1} 50%{opacity:0.4} }
        @keyframes slideUp { from{opacity:0;transform:translateY(6px)} to{opacity:1;transform:translateY(0)} }
        @keyframes spin { to{transform:rotate(360deg)} }
        @keyframes scanline {
          0%{transform:translateY(-100%)} 100%{transform:translateY(100vh)}
        }
        .scan { animation: scanline 4s linear infinite; }
        .pulse-dot { animation: pulse 1.5s ease infinite; }
        .slide-up { animation: slideUp 0.4s ease; }
        .metric-card:hover { border-color: var(--panel-color) !important; transform: translateY(-1px); }
        .metric-card { transition: all 0.2s; cursor: default; }
        .panel-tab { transition: all 0.2s; cursor: pointer; border: none; background: transparent; }
        .panel-tab:hover { opacity: 0.9; }
        .event-row:hover { background: rgba(255,255,255,0.03) !important; }
        .event-row { transition: background 0.2s; }
        .defcon-region { cursor: pointer; transition: all 0.2s; }
        .defcon-region:hover { opacity: 0.85; transform: scale(1.02); }
      `}</style>

      {/* ── SCANLINE EFFECT ── */}
      <div className="scan" style={{
        position: "fixed", top: 0, left: 0, right: 0, height: "2px",
        background: "linear-gradient(90deg, transparent, #22c55e22, transparent)",
        pointerEvents: "none", zIndex: 999,
      }} />

      {/* ── TOP HEADER ── */}
      <div style={{
        background: "linear-gradient(90deg, #0a1628 0%, #0f1f3d 50%, #0a1628 100%)",
        borderBottom: "1px solid #1e293b",
        padding: "0 20px",
        display: "flex", alignItems: "center", gap: 16,
        height: 56, flexShrink: 0,
      }}>
        {/* Logo + Title */}
        <div style={{ display: "flex", alignItems: "center", gap: 10, flexShrink: 0 }}>
          <img src={LOGO_B64} alt="MW" style={{ width: 36, height: 36, objectFit: "contain", filter: "drop-shadow(0 0 6px #22c55e88)" }} />
          <div>
            <div style={{ fontSize: 13, fontWeight: 800, color: "#22c55e", letterSpacing: 1 }}>
              MENA<span style={{ color: "#f8fafc" }}>.Watch</span>
            </div>
            <div style={{ fontSize: 9, color: "#475569", letterSpacing: 2 }}>غرفة العمليات</div>
          </div>
        </div>

        <div style={{ width: 1, height: 32, background: "#1e293b", flexShrink: 0 }} />

        {/* Live markets strip */}
        {[
          { l: "تاسي", v: "12,847", c: "+0.4%", up: true },
          { l: "برنت", v: "$82.1",  c: "-0.8%", up: false },
          { l: "ذهب",  v: "$2,318", c: "+0.3%", up: true },
          { l: "SAR",  v: "3.751",  c: "ثابت",  up: null },
        ].map(s => (
          <div key={s.l} style={{ textAlign: "center", flexShrink: 0 }}>
            <div style={{ fontSize: 9, color: "#475569" }}>{s.l}</div>
            <div style={{ fontSize: 12, fontWeight: 700, color: "#f8fafc", fontVariantNumeric: "tabular-nums" }}>{s.v}</div>
            <div style={{ fontSize: 9, color: s.up === true ? "#22c55e" : s.up === false ? "#ef4444" : "#64748b" }}>{s.c}</div>
          </div>
        ))}

        <div style={{ flex: 1 }} />

        {/* News ticker */}
        <div style={{
          flex: "0 0 380px",
          background: "#0a0f1e",
          border: "1px solid #1e293b",
          borderRadius: 4,
          padding: "5px 12px",
          overflow: "hidden",
          display: "flex", alignItems: "center", gap: 8,
        }}>
          <span style={{ background: "#ef4444", color: "#fff", fontSize: 8, fontWeight: 700, padding: "2px 5px", borderRadius: 2, flexShrink: 0, letterSpacing: 1 }}>عاجل</span>
          <div className="slide-up" key={newsIdx} style={{ fontSize: 11, color: "#94a3b8", whiteSpace: "nowrap", overflow: "hidden", textOverflow: "ellipsis" }}>
            {allEvents[newsIdx]?.text}
          </div>
        </div>

        {/* Clock */}
        <div style={{ textAlign: "center", flexShrink: 0 }}>
          <div style={{ fontSize: 9, color: "#475569" }}>توقيت الرياض</div>
          <div style={{ fontSize: 14, fontWeight: 700, color: "#22c55e", fontVariantNumeric: "tabular-nums", letterSpacing: 1 }}>{saudiTime}</div>
          <div style={{ fontSize: 8, color: "#334155" }}>{saudiDate}</div>
        </div>
      </div>

      {/* ── DEFCON BAR ── */}
      <div style={{
        background: "#080f1c",
        borderBottom: "1px solid #1e293b",
        padding: "6px 20px",
        display: "flex", alignItems: "center", gap: 12, flexShrink: 0,
      }}>
        <span style={{ fontSize: 10, color: "#475569", flexShrink: 0 }}>مؤشر DEFCON الإقليمي:</span>
        <div style={{ display: "flex", gap: 6, flex: 1 }}>
          {DEFCON_REGIONS.map(r => {
            const dm = DEFCON_META[r.level];
            const isActive = defconRegion === r.id;
            return (
              <div
                key={r.id}
                className="defcon-region"
                onClick={() => setDefconRegion(r.id)}
                style={{
                  display: "flex", alignItems: "center", gap: 5,
                  padding: "3px 10px",
                  borderRadius: 4,
                  background: isActive ? dm.bg : "transparent",
                  border: `1px solid ${isActive ? dm.border : "#1e293b"}`,
                }}
              >
                <div style={{
                  width: 7, height: 7, borderRadius: "50%",
                  background: dm.border,
                  ...(r.level <= 3 ? { animation: "pulse 1s infinite" } : {}),
                }} />
                <span style={{ fontSize: 10, color: isActive ? dm.color : "#64748b", fontWeight: isActive ? 700 : 400 }}>
                  {r.name}
                </span>
                <span style={{
                  fontSize: 9, fontWeight: 700,
                  color: dm.border,
                  background: dm.bg,
                  padding: "1px 5px", borderRadius: 3,
                }}>D{r.level}</span>
                {r.level < r.prev && <span style={{ fontSize: 8, color: "#ef4444" }}>↑</span>}
                {r.level > r.prev && <span style={{ fontSize: 8, color: "#22c55e" }}>↓</span>}
              </div>
            );
          })}
        </div>
        <div style={{
          flexShrink: 0, padding: "3px 12px",
          background: defcon.bg,
          border: `1px solid ${defcon.border}`,
          borderRadius: 4,
          fontSize: 10, fontWeight: 700, color: defcon.color,
        }}>
          {region?.name}: {defcon.label} (D{region?.level})
        </div>
      </div>

      {/* ── PANEL TABS ── */}
      <div style={{
        background: "#080f1c",
        borderBottom: "1px solid #1e293b",
        padding: "0 20px",
        display: "flex", gap: 2, flexShrink: 0,
      }}>
        {PANELS.map(p => (
          <button
            key={p.id}
            className="panel-tab"
            onClick={() => { setActivePanel(p.id); setAiText(""); }}
            style={{
              padding: "10px 16px",
              fontSize: 12, fontWeight: 600,
              fontFamily: "inherit",
              color: activePanel === p.id ? p.color : "#64748b",
              borderBottom: `2px solid ${activePanel === p.id ? p.color : "transparent"}`,
              display: "flex", alignItems: "center", gap: 6,
            }}
          >
            <span>{p.icon}</span> {p.title}
          </button>
        ))}
      </div>

      {/* ── MAIN CONTENT ── */}
      <div style={{ flex: 1, display: "flex", overflow: "hidden", gap: 0 }}>

        {/* LEFT — Metrics + Events (70%) */}
        <div style={{ flex: "0 0 70%", display: "flex", flexDirection: "column", overflow: "hidden", borderLeft: "1px solid #1e293b" }}>

          {/* Metrics row */}
          <div style={{
            display: "grid", gridTemplateColumns: "repeat(4, 1fr)",
            gap: 12, padding: "14px 16px",
            borderBottom: "1px solid #1e293b",
            flexShrink: 0,
          }}>
            {panel.metrics.map((m, i) => (
              <div
                key={i}
                className="metric-card"
                style={{
                  background: "#0a1628",
                  border: `1px solid #1e293b`,
                  borderRadius: 8,
                  padding: "12px 14px",
                  "--panel-color": panel.color,
                }}
              >
                <div style={{ fontSize: 9, color: "#475569", marginBottom: 6 }}>{m.label}</div>
                <div style={{ display: "flex", alignItems: "baseline", gap: 4 }}>
                  <span style={{ fontSize: 22, fontWeight: 800, color: panel.color, fontVariantNumeric: "tabular-nums" }}>{m.val}</span>
                  <span style={{ fontSize: 10, color: "#64748b" }}>{m.unit}</span>
                </div>
                <div style={{ marginTop: 6, display: "flex", alignItems: "center", gap: 4 }}>
                  <span style={{ fontSize: 13, color: m.trend === "↑" ? "#22c55e" : m.trend === "↓" ? "#ef4444" : "#64748b" }}>{m.trend}</span>
                  <span style={{ fontSize: 9, color: "#64748b" }}>{m.delta}</span>
                </div>
              </div>
            ))}
          </div>

          {/* Events feed */}
          <div style={{ flex: 1, overflow: "auto", padding: "0 16px" }}>
            <div style={{ padding: "10px 0 6px", display: "flex", alignItems: "center", gap: 8 }}>
              <div className="pulse-dot" style={{ width: 6, height: 6, borderRadius: "50%", background: panel.color }} />
              <span style={{ fontSize: 11, fontWeight: 700, color: "#475569" }}>أحداث {panel.title} — آخر 24 ساعة</span>
            </div>
            {panel.events.map((e, i) => (
              <div
                key={i}
                className="event-row slide-up"
                style={{
                  display: "flex", gap: 12, alignItems: "flex-start",
                  padding: "10px 0",
                  borderBottom: "1px solid #0f172a",
                }}
              >
                <div style={{
                  flexShrink: 0, width: 40,
                  fontSize: 10, color: "#475569",
                  fontVariantNumeric: "tabular-nums",
                  paddingTop: 2,
                }}>{e.time}</div>
                <div style={{
                  width: 4, flexShrink: 0, alignSelf: "stretch",
                  borderRadius: 2,
                  background: SEVERITY_STYLE[e.severity].dot,
                }} />
                <div style={{
                  flex: 1,
                  background: SEVERITY_STYLE[e.severity].bg,
                  borderRadius: 6,
                  padding: "8px 12px",
                  fontSize: 12, color: "#cbd5e1", lineHeight: 1.6,
                }}>{e.text}</div>
              </div>
            ))}
          </div>
        </div>

        {/* RIGHT — DEFCON detail + AI Analysis (30%) */}
        <div style={{
          flex: "0 0 30%",
          background: "#080f1c",
          borderRight: "1px solid #1e293b",
          display: "flex", flexDirection: "column", overflow: "hidden",
        }}>

          {/* DEFCON detail card */}
          <div style={{ padding: 16, borderBottom: "1px solid #1e293b", flexShrink: 0 }}>
            <div style={{ fontSize: 10, color: "#475569", marginBottom: 10 }}>مؤشر DEFCON المنطقة المختارة</div>
            <div style={{
              background: defcon.bg,
              border: `1px solid ${defcon.border}`,
              borderRadius: 10,
              padding: "14px 16px",
            }}>
              <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between", marginBottom: 10 }}>
                <span style={{ fontSize: 16, fontWeight: 800, color: defcon.color }}>{region?.name}</span>
                <span style={{
                  fontSize: 28, fontWeight: 900, color: defcon.border,
                  fontVariantNumeric: "tabular-nums",
                  textShadow: `0 0 20px ${defcon.border}`,
                }}>D{region?.level}</span>
              </div>
              <div style={{ fontSize: 13, fontWeight: 700, color: defcon.color, marginBottom: 8 }}>{defcon.label}</div>
              {/* DEFCON scale visual */}
              <div style={{ display: "flex", gap: 3, marginBottom: 8 }}>
                {[1,2,3,4,5].map(n => (
                  <div key={n} style={{
                    flex: 1, height: 6, borderRadius: 3,
                    background: n <= (6 - (region?.level || 5))
                      ? defcon.border
                      : "#1e293b",
                    transition: "background 0.3s",
                  }} />
                ))}
              </div>
              <div style={{ fontSize: 9, color: "#475569" }}>
                {region?.level < region?.prev ? "⚠️ تصاعد من D" + region?.prev : region?.level > region?.prev ? "✅ تحسن من D" + region?.prev : "مستقر"}
              </div>
            </div>

            {/* All regions quick view */}
            <div style={{ marginTop: 10, display: "flex", flexWrap: "wrap", gap: 4 }}>
              {DEFCON_REGIONS.map(r => {
                const dm = DEFCON_META[r.level];
                return (
                  <div
                    key={r.id}
                    className="defcon-region"
                    onClick={() => setDefconRegion(r.id)}
                    style={{
                      padding: "3px 8px",
                      borderRadius: 4,
                      background: dm.bg,
                      border: `1px solid ${defconRegion === r.id ? dm.border : "#1e293b"}`,
                      fontSize: 9, color: dm.color,
                      display: "flex", alignItems: "center", gap: 4,
                    }}
                  >
                    <span>{r.name}</span>
                    <span style={{ fontWeight: 700 }}>D{r.level}</span>
                  </div>
                );
              })}
            </div>
          </div>

          {/* AI Compound Analysis */}
          <div style={{ flex: 1, overflow: "auto", padding: 16, display: "flex", flexDirection: "column", gap: 12 }}>
            <div style={{ display: "flex", alignItems: "center", justifyContent: "space-between" }}>
              <div style={{ fontSize: 10, color: "#475569", display: "flex", alignItems: "center", gap: 6 }}>
                <div className="pulse-dot" style={{ width: 5, height: 5, borderRadius: "50%", background: "#22c55e" }} />
                التحليل المركّب — Claude AI
              </div>
              <button
                onClick={fetchCompoundAI}
                disabled={aiLoading}
                style={{
                  background: aiLoading ? "#1e293b" : "#22c55e18",
                  border: "1px solid #22c55e44",
                  borderRadius: 5,
                  color: "#22c55e",
                  fontSize: 10,
                  fontFamily: "inherit",
                  padding: "4px 10px",
                  cursor: aiLoading ? "default" : "pointer",
                }}
              >
                {aiLoading ? "⏳ جاري التحليل..." : "🔍 تحليل لحظي"}
              </button>
            </div>

            {/* AI result */}
            {aiText && (
              <div className="slide-up" style={{
                background: "#0a1628",
                border: "1px solid #22c55e33",
                borderRadius: 8,
                padding: 12,
                fontSize: 11, color: "#94a3b8", lineHeight: 1.8,
              }}>
                {aiText}
              </div>
            )}

            {/* Compound scenarios */}
            <div style={{ fontSize: 10, color: "#475569", marginTop: 4 }}>سيناريوهات التحليل المركّب:</div>
            {COMPOUND_ANALYSIS.map(c => (
              <div key={c.id} style={{
                background: "#0a1628",
                border: "1px solid #1e293b",
                borderRadius: 8,
                padding: 12,
                fontSize: 11,
              }}>
                <div style={{ color: "#64748b", marginBottom: 6, lineHeight: 1.5, fontSize: 10 }}>{c.title}</div>
                <div style={{ color: "#e2e8f0", lineHeight: 1.6, marginBottom: 8 }}>{c.conclusion}</div>
                <div style={{ display: "flex", gap: 6, flexWrap: "wrap" }}>
                  <span style={{ background: "#1e293b", color: "#94a3b8", padding: "2px 7px", borderRadius: 3, fontSize: 9 }}>⏱ {c.horizon}</span>
                  <span style={{ background: c.confidence >= 75 ? "#14532d" : c.confidence >= 55 ? "#78350f" : "#1e293b", color: c.confidence >= 75 ? "#22c55e" : c.confidence >= 55 ? "#f59e0b" : "#64748b", padding: "2px 7px", borderRadius: 3, fontSize: 9 }}>ثقة {c.confidence}%</span>
                  <span style={{ background: "#1e3a5f", color: "#93c5fd", padding: "2px 7px", borderRadius: 3, fontSize: 9 }}>{c.sector}</span>
                  <span style={{ background: c.impact === "إيجابي" ? "#14532d" : "#78350f", color: c.impact === "إيجابي" ? "#22c55e" : "#f59e0b", padding: "2px 7px", borderRadius: 3, fontSize: 9 }}>{c.impact}</span>
                </div>
              </div>
            ))}
          </div>

          {/* Register CTA */}
          <div style={{ padding: "10px 16px", borderTop: "1px solid #1e293b", background: "#060d18", flexShrink: 0 }}>
            <div style={{
              background: "linear-gradient(135deg, #22c55e18, #22c55e08)",
              border: "1px solid #22c55e33",
              borderRadius: 8,
              padding: "10px 12px",
              textAlign: "center",
            }}>
              <div style={{ fontSize: 10, color: "#e2e8f0", marginBottom: 6 }}>⭐ افتح غرفة العمليات الكاملة</div>
              <button style={{
                background: "#22c55e", color: "#fff", border: "none",
                borderRadius: 6, padding: "7px 16px",
                fontSize: 11, fontWeight: 700, fontFamily: "inherit",
                cursor: "pointer", width: "100%",
              }}>
                حساب الخبير — سجّل الآن
              </button>
            </div>
          </div>
        </div>
      </div>
    </div>
  );
}
